import React from "react";
import { motion, useAnimation } from "framer-motion";
import { useInView } from "react-intersection-observer"; // Fixed: removed the underscore

const About = (props) => {
  const controls = useAnimation();
  const [ref, inView] = useInView({ threshold: 0.3 }); // Fixed: removed the underscore

  React.useEffect(() => {
    if (inView) {
      controls.start("visible");
    } else {
      controls.start("hidden");
    }
  }, [inView, controls]);

  let sectionName, hello, about;
  if (props.resumeBasicInfo) {
    sectionName = props.resumeBasicInfo.section_name.about;
    hello = props.resumeBasicInfo.description_header;
    about = props.resumeBasicInfo.description;
  }

  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: { staggerChildren: 0.3 }
    }
  };

  const itemVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: { opacity: 1, y: 0, transition: { duration: 0.6 } }
  };

  return (
    <section id="about" ref={ref} style={{ padding: "100px 0", position: "relative", overflow: "hidden", background: "#f8f5f4" }}>
      {/* Decorative background blob */}
      <motion.div 
        animate={{ 
          scale: [1, 1.1, 1],
          rotate: [0, 90, 0]
        }}
        transition={{ duration: 20, repeat: Infinity, ease: "linear" }}
        style={{
          position: "absolute",
          top: "-10%",
          right: "-5%",
          width: "500px",
          height: "500px",
          background: "radial-gradient(circle, rgba(233,213,161,0.2) 0%, rgba(186,170,128,0) 70%)",
          filter: "blur(60px)",
          zIndex: 0
        }}
      />

      <div className="container">
        <motion.div 
          className="row"
          initial="hidden"
          animate={controls}
          variants={containerVariants}
        >
          <div className="col-md-12" style={{ zIndex: 1 }}>
            <motion.h1 
              variants={itemVariants}
              style={{ textAlign: "center", marginBottom: "60px", fontWeight: "700", letterSpacing: "3px", textTransform: "uppercase", color: "#353239" }}
            >
              {sectionName}
            </motion.h1>
          </div>

          {/* Profile Picture Column */}
          <div className="col-md-4 mb-5 d-flex justify-content-center" style={{ zIndex: 1 }}>
            <motion.div 
              variants={itemVariants}
              style={{ position: "relative", width: "280px", height: "320px" }}
            >
              {/* Profile Image */}
              <img
                src="https://github.com/06Aditya.png"
                src = "/home/helios/react-frontend-dev-portfolio-main/public/images/myProfile.jpg"
                alt="Aditya Profile"
                style={{
                  width: "100%",
                  height: "100%",
                  objectFit: "cover",
                  borderRadius: "20px",
                  boxShadow: "0 20px 40px rgba(0,0,0,0.12)",
                  border: "5px solid white",
                  position: "relative",
                  zIndex: 2
                }}
              />

              {/* Perfectly Centered Decorative Frame */}
              <div style={{
                position: "absolute",
                top: "-10px", 
                left: "-10px",
                width: "calc(100% + 20px)",
                height: "calc(100% + 20px)",
                border: "2px solid #AE944F",
                borderRadius: "25px", 
                zIndex: 1
              }} />
            </motion.div>
          </div>

          {/* Bio Column */}
          <div className="col-md-8" style={{ zIndex: 1 }}>
            <motion.div 
              variants={itemVariants}
              style={{
                background: "rgba(255, 255, 255, 0.7)",
                backdropFilter: "blur(12px)",
                padding: "45px",
                borderRadius: "30px",
                border: "1px solid rgba(255, 255, 255, 0.4)",
                boxShadow: "0 15px 35px rgba(0,0,0,0.05)"
              }}
            >
              <h2 style={{ marginBottom: "25px", fontWeight: "600", color: "#AE944F" }}>
                {hello} <motion.span 
                  animate={{ rotate: [0, 15, -15, 0] }} 
                  transition={{ repeat: Infinity, duration: 2, repeatDelay: 1 }}
                  style={{ display: "inline-block" }}
                >👋</motion.span>
              </h2>
              <p style={{ 
                fontSize: "1.6rem", 
                lineHeight: "1.8", 
                color: "#444",
                textAlign: "justify",
                fontFamily: "'Segoe UI', Roboto, Helvetica, Arial, sans-serif"
              }}>
                {about}
              </p>
            </motion.div>
          </div>
        </motion.div>
      </div>
    </section>
  );
};

export default About;
